class LogsController < ApplicationController
  def show
    @filename = params[:log] # Get filename via param in URL (e.g., /admin/show?log=my_file)
    
    if Rails.env.development? || Rails.application.config.consider_all_requests_local  
      path = File.join(Rails.root, 'log', @filename + '.txt') # Path to log file in logs directory (e.g., /path/to/yourapp/log/) 
    else
       return not_found unless File.exist?(path) && !File.directory?(path)  
      path = Rails.root.join('log', @filename + '.txt') # Path to log file in logs directory (e.g., /yourapp/public/) 
    end    
      
    content = File.read(path, encoding: 'utf-8');# Read the contents of a textfile into string  
     
    respond_to do |format| # Respond to different formats like HTML or JSON (default is plaintext)
        format.html { render html: content } 
       end    
end